import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // --- Empty / trivial ---
  it.todo("empty item list → premium 5 G (only the processing fee)");

  // --- Base premiums for main items (with 5 G processing fee added) ---
  it.todo("quote with a single plain sword → premium 105 G (100 base + 5 fee)");
  it.todo("quote with a single plain amulet → premium 65 G (60 base + 5 fee)");
  it.todo("quote with a single plain staff → premium 85 G (80 base + 5 fee)");
  it.todo("quote with a single plain potion → premium 45 G (40 base + 5 fee)");

  // --- Component pricing & blocks of 3 ---
  it.todo("quote with 2 runes → premium 55 G (50 base + 5 fee)");
  it.todo("quote with 3 runes → premium 65 G (60 base block + 5 fee)");
  it.todo("quote with 4 runes → premium 105 G (100 base, no block + 5 fee)");
  it.todo("quote with 7 runes → premium 180 G (175 base + 5 fee)");

  // --- 'Alike' components (clarifying question) ---
  it.todo("quote with 2 runes + 1 moonstone → premium 80 G (75 base, no block) ");
  it.todo("quote with 3 runes + 3 moonstones → premium 125 G (120 base = two blocks + 5 fee)");

  // --- Item-specific modifiers (cursed, high enchantment) on a single item ---
  it.todo("quote with cursed sword (steel, ench 3), 0 years, first contract → premium 165 G (newcomer integration example)");
  it.todo("quote with sword ench 5 (not cursed), 0 years, first contract → premium 145 G (100 + 30 high-ench + 10 first = 140 + 5)");
  it.todo("quote with sword ench 4 (not cursed), 0 years, first contract → premium 115 G (100 + 10 first + 5)");
  it.todo("quote with cursed sword ench 5, 0 years, first contract → premium 195 G (100 + 50 curse + 30 high-ench + 10 first = 190 + 5)");

  // --- Policy-wide modifier scope (cursed surcharge applies to cursed item only) ---
  it.todo("quote with cursed sword + plain amulet, 0 years, first → premium 235 G (160 base + 50 curse + 16 first ceil = 226 + 5 fee→ check spec: 210 G before further modifiers and fee; with first 10% on 160 = 16 → 226 + 5 = 231? verify against integration)");
  // Note: the spec says 210 G 'before further modifiers and fee' for cursed sword + amulet — used to verify scope.
  it.todo("scope check: cursed sword + plain amulet (no other modifiers, no first-insurance) → 215 G (160 base + 50 curse + 5 fee)");

  // --- Modifier thresholds ---
  it.todo("loyalty discount applies at exactly 2 years with MHPCO");
  it.todo("high-enchantment surcharge applies at exactly enchantment 5");
  it.todo("no high-enchantment surcharge at enchantment 4");

  // --- Long-standing customer's second contract (integration example) ---
  it.todo("3-year customer, second quote: cursed sword ench 7 → premium 160 G (integration example)");

  // --- Rounding (in MHPCO's favor) ---
  it.todo("premium that yields 197.5 G → 198 G (rounded up)");
  it.todo("payout that yields 350.5 G → 350 G (rounded down)");

  // --- Claim: standard reimbursement ---
  it.todo("regular sword (steel, ench 3), damage 500 G → payout 400 G (500 - 100 deductible)");
  it.todo("damage to a rune (value 250 G), damage 200 G → payout 100 G (200 - 100 deductible)");

  // --- Claim: high-enchantment clause ---
  it.todo("steel sword ench 9, damage 1000 G → payout 400 G (50% then -100 deductible)");

  // --- Claim: dragon material clause ---
  it.todo("dragon sword ench 5, damage 800 G → payout 700 G (full minus deductible)");

  // --- Claim: enchantment threshold + dragon material (50% wins) ---
  it.todo("dragon sword ench 9, damage 1000 G → payout 400 G (50% wins, then deductible)");
  it.todo("dragon sword ench exactly 8, damage 1000 G → payout 400 G (high-ench applies, then deductible)");

  // --- Claim: deductible applies per damaged item ---
  it.todo("dragon attack: sword 500 G + amulet 300 G damage → payout 600 G (deductible per item)");

  // --- Claim: multiple items of same type ---
  it.todo("policy with two swords; insurance sum 2000 G, cap 4000 G; dragon attack damages both → each damage entry treated separately with own deductible");
  it.todo("policy with one sword but damages contains two sword entries → CLI exits non-zero (claim rejected)");

  // --- Cap exhaustion ---
  it.todo("policy: sword + amulet → insurance sum 1600 G, cap 3200 G");
  it.todo("cursed sword → cap is 2000 G (based on unmodified insurance value)");
  it.todo("policy: sword + 3 runes → insurance sum 1750 G (block discount does not affect insurance sum)");
  it.todo("sword (cap 2000): two successive 1500 G claims → first payout 1400, remainingCap 600; second payout 600, remainingCap 0");

  // --- Edge cases ---
  it.todo("quote includes unknown item type (e.g. broomstick) → CLI exits non-zero, stderr describes error, no results on stdout");
  it.todo("claim references damage for item not in the policy → CLI exits non-zero");
  it.todo("claim contains a damage entry with negative amount → CLI exits non-zero");
});

