import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // --- Empty / trivial ---
  it("empty item list → premium 5 G (only the processing fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });

  // --- Base premiums for main items (with 5 G processing fee added) ---
  it("plain sword, 0 yrs first contract → premium 115 G (100 base + 10 first + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", material: "steel", enchantment: 1, cursed: false }] }],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it.todo("plain amulet → premium 65 G (60 base + 5 fee)");
  it.todo("plain staff → premium 85 G (80 base + 5 fee)");
  it.todo("plain potion → premium 45 G (40 base + 5 fee)");

  // --- Component pricing & blocks of 3 ---
  it.todo("2 runes → premium 55 G (50 base + 5 fee)");
  it.todo("3 runes → premium 65 G (60 base block + 5 fee)");
  it.todo("4 runes → premium 105 G (100 base, no block + 5 fee)");
  it.todo("7 runes → premium 180 G (175 base + 5 fee)");

  // --- 'Alike' components clarifying question ---
  it.todo("2 runes + 1 moonstone → premium 80 G (75 base, no block + 5 fee)");
  it.todo("3 runes + 3 moonstones → premium 125 G (120 base = two blocks + 5 fee)");

  // --- Item-specific modifiers on a single item (also integration: newcomer) ---
  it.todo("newcomer (0 yrs, first contract), cursed sword (steel, ench 3) → premium 165 G");
  it.todo("0-yr first-contract customer, sword ench 5, not cursed → premium 145 G (100 + 30 high-ench + 10 first + 5 fee)");
  it.todo("0-yr first-contract customer, sword ench 4, not cursed → premium 115 G (100 + 10 first + 5 fee)");
  it.todo("0-yr first-contract customer, cursed sword ench 5 → premium 195 G (100 + 50 + 30 + 10 + 5)");

  // --- Modifier scope on multi-item policies (spec ❓) ---
  it.todo("cursed sword + plain amulet, 0 yrs first contract → premium 231 G (160 base + 50 curse + 16 first 10% of policy base + 5 fee)");

  // --- Modifier thresholds ---
  it.todo("loyalty discount applies at exactly 2 years with MHPCO");
  it.todo("3-year customer, second quote in scenario, cursed sword ench 7 → premium 160 G (integration example)");

  // --- Rounding (in MHPCO's favor) ---
  it.todo("premium that yields 197.5 G → 198 G (rounded up)");
  it.todo("payout that yields 350.5 G → 350 G (rounded down)");

  // --- Claim: standard reimbursement ---
  it.todo("regular sword (steel, ench 3), damage 500 G → payout 400 G");
  it.todo("rune (insurance value 250 G), damage 200 G → payout 100 G");

  // --- Claim: high-enchantment clause ---
  it.todo("steel sword ench 9, damage 1000 G → payout 400 G (50% then -100 deductible)");

  // --- Claim: dragon material clause ---
  it.todo("dragon sword ench 5, damage 800 G → payout 700 G (full minus deductible)");

  // --- Claim: enchantment threshold vs dragon material ---
  it.todo("dragon sword ench 9, damage 1000 G → payout 400 G (50% wins, then deductible)");
  it.todo("dragon sword ench exactly 8, damage 1000 G → payout 400 G (high-ench applies, then deductible)");

  // --- Claim: deductible per damaged item ---
  it.todo("dragon attack: sword 500 G + amulet 300 G damage on same incident → payout 600 G (deductible per item)");

  // --- Claim: multiple items of same type ---
  it.todo("policy with two swords: insurance sum 2000 G, cap 4000 G; dragon attack damages both swords (two damage entries) → each treated separately with own deductible");
  it.todo("policy with one sword but damages contains two sword entries → CLI exits non-zero (claim rejected)");

  // --- Cap exhaustion ---
  it.todo("policy: sword + amulet → insurance sum 1600 G, cap 3200 G (verified via claim remainingCap)");
  it.todo("cursed sword → cap is 2000 G based on unmodified insurance value");
  it.todo("policy: sword + 3 runes → insurance sum 1750 G (block discount does not affect insurance sum)");
  it.todo("sword (cap 2000): two successive 1500 G claims → first payout 1400 remCap 600; second payout 600 remCap 0");

  // --- Edge cases ---
  it.todo("quote includes unknown item type (e.g. broomstick) → CLI exits non-zero, stderr has error, no results on stdout");
  it.todo("claim references damage for an item type not in the policy → CLI exits non-zero");
  it.todo("claim contains damage entry with negative amount → CLI exits non-zero");
});

