type Item = { type: string };
type Step = { op: "quote"; items: Item[] };
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
};

export function runScenario(input: Scenario): { results: { premium: number }[] } {
  const results = input.steps.map((step) => {
    let total = 0;
    for (const item of step.items) {
      const base = BASE_PREMIUM[item.type] ?? 0;
      total += base + base * 0.1; // first-insurance surcharge per item
    }
    return { premium: Math.ceil(total) + 5 };
  });
  return { results };
}

