type Item = { type: string };
type Step = { op: "quote"; items: Item[] };
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

const MAIN_BASE: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};
const COMPONENT_TYPES = new Set(["rune"]);
const COMPONENT_BASE = 25;
const COMPONENT_BLOCK_OF_3 = 60;

function policyBase(items: Item[]): number {
  let total = 0;
  const componentCounts = new Map<string, number>();
  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) {
      componentCounts.set(item.type, (componentCounts.get(item.type) ?? 0) + 1);
    } else {
      total += MAIN_BASE[item.type] ?? 0;
    }
  }
  for (const count of componentCounts.values()) {
    const blocks = Math.floor(count / 3);
    const remainder = count - blocks * 3;
    total += blocks * COMPONENT_BLOCK_OF_3 + remainder * COMPONENT_BASE;
  }
  return total;
}

export function runScenario(input: Scenario): { results: { premium: number }[] } {
  const results = input.steps.map((step) => {
    const base = policyBase(step.items);
    const firstInsurance = base * 0.1;
    return { premium: Math.ceil(base + firstInsurance) + 5 };
  });
  return { results };
}

